window.__dh_data["mr"] = {
  "": "Content-Type: text/plain; charset=UTF-8\nContent-Transfer-Encoding: 8bit\n",
  "title": "धम्मपद",
  "chaps": "प्रकरणे",
  "fontsize": "अक्षरांचा आकार",
  "chap1": "यमकवग्गो",
  "1": "स्वभावाच्या पुढे मन असते, मन (सर्व)श्रेष्ठ आहे, विकृत मनाने बोलतो वा कृती करतो तेंव्हा त्याच्या मागे दुक्ख असे येते, जसे (बैलाच्या) पावलांमागे चाक जाते ।",
  "2": "स्वभावाच्या पुढे मन असते, मन (सर्व)श्रेष्ठ आहे, प्रसन्न मनाने बोलतो वा कृती करतो तेंव्हा त्याच्या मागे सुख असे येते, जशी सावली ॥",
  "3": "मला अपमानिले, माझा शेवट केला, मला जिंकले, जे असे वैर धरतात, त्यांचे वैर शमत नाही ।",
  "4": "मला अपमानिले, माझा शेवट केला, मला जिंकले, जे असे वैर न धरतात, त्यांचेच वैर शमते ॥",
  "5": "वैराने वैर कधीही शमत नाही, ते अवैरानेच शमते, असा पूर्वापार सिद्धांत आहे ।",
  "6": "त्यांचे नव्हे, आपण मरणारच आहोत हे जे जाणत नाहीत, त्यांचेच वैर शमते, आपण मरणारच आहोत हे जे जाणतात ॥",
  "7": "(फक्त) चांगलेच पहात फिरणारा, इंद्रियांवर ताबा नसलेला, भोजनाची (योग्य) मात्रा न जाणणारा, निरुद्योगी, हिंमत हारलेला, त्याला, भुलैया असे जिंकतो, जसे वारा दुर्बल झाडाला (वाकवितो) ।",
  "8": "(फक्त) चांगलेच न पहात फिरणारा, इंद्रियांवर योग्य ताबा असलेला, भोजनाची (योग्य) मात्रा जाणणारा, प्रयत्नशील, हिंमतवान, त्याला, भुलैया जिंकू शकत नाही, जसे वारा शैल पर्वताला हलवू शकत नाही ॥",
  "9": "मलयुक्त चित्ताने जो भगवी वस्त्रे परिधान करतो तो, सत्य व संयमाहून दूर गेलेला, भगवी वस्त्रे धारण करण्यास लायक नाही ।",
  "10": "जो दोषविरहित आहे, शीलवान आहे, चांगला एकाग्रचित्त आहे, सत्य व संयमाजवळ असणारा, तो भगवी वस्त्रे धारण करण्यास लायक आहे ॥",
  "11": "सत्वहीनात सत्व पहाणारा, सात्विकात सत्वहीनता पहाणारा, खोटे संकल्प पहाणारा (करणारा) सात्विकता प्राप्त करीत नाही ।",
  "12": "सात्विकतेतच सत्व पहाणारा, सत्वहीनतेत असत्व पहाणारा, सम्यक संकल्प पहाणारा (करणारा) सात्विकता प्राप्त करतो ॥",
  "13": "जसे छतविरहित घरात पाऊस आरपार जातो, तसे अननुभवीच्या (मानवाच्या) मनात रागाचा प्रवेश होतो ।",
  "14": "जसे चांगल्या छताच्या घरात पाऊस प्रवेश करीत नाही, तसे अनुभवीच्या (मानवाच्या) मनात रागाचा प्रवेश होत नाही ॥",
  "15": "इथेही चिंतित, मृत्योत्तरही चिंतित, दुष्कर्मी दोन्हीकडे चिंतित असतात, ते केलेल्या कुकर्मांना पाहून चिंतित होतात, पीडित होतात ।",
  "16": "इथेही आनंदित, मृत्योत्तरही आनंदित, सत्कर्मी दोन्हीकडे आनंदित असतात, ते केलेल्या सत्कर्मांना पाहून आनंदित होतात, अधिक आनंदित होतात ॥",
  "17": "इथेही तप्त, मृत्योत्तरही तप्त, दुष्कर्मी दोन्हीकडे तप्त असतात, ते केलेल्या कुकर्मांना पाहून तप्त होतात, दुर्गतीकडे जातात ।",
  "18": "इथेही प्रसन्न, मृत्योत्तरही प्रसन्न, सत्कर्मी दोन्हीकडे प्रसन्न असतात, 'मी सत्कर्म केले' (या विचारांनी) प्रसन्न होतात, अधिक प्रसन्न होतात ॥",
  "19": "पुष्कळ (ग्रंथ) वाचून तस्कर वा प्रमादी मानव (भाग्यवान, श्रमण होत नाही), दुसऱ्यांच्या गाई मोजून गो-पालक भाग्यवान, श्रमण होत नाही ।",
  "20": "थोडेसेच (ग्रंथ) वाचून सैद्धांतिक आचरणाने सदाचारी होतो, राग, द्वेष, मोह त्यागून, सम्यक जाणिवेने, मुक्त चित्ताने, अनासक्त, असा (मानव) भाग्यवान, श्रमण होतो ॥",
  "chap2": "अप्पमादवग्गो",
  "21": "अप्रमाद अमृत स्थान आहे, प्रमाद (बेपर्वा) मृत्यूचे स्थान आहे, अप्रमादी मृत होत नाहीत, प्रमादी मृतवत असतात ।",
  "22": "अप्रमादाची ही विशेषता ज्ञानी जन जाणतात की, अप्रमादात आर्याचरणी (सदाचरणी) प्रसन्न-मग्न असतात ॥",
  "23": "ध्यानमग्न, जागृत, दृढ पराक्रमी, ज्ञानी (मानव) यत्न-सिद्ध कल्याण, निर्वाण प्राप्त करतो ।",
  "24": "उद्योगी, जागृत, सुकर्मी, विचारवंत, संयमाने व सदाचाराने (धम्माप्रमाणे) जगणाऱ्या, अप्रमादी (मानवा)ची यशवृद्धी होते ॥",
  "25": "अप्रमादी (मानव) उद्योगाने, संयमाने, शक्तीने, प्रज्ञावान असे बेट उभारतो, ज्यास पूर बुडवू शकत नाही ।",
  "26": "अज्ञानी, दुर्बुद्ध (मानव) प्रमाद करतात, प्रज्ञावान श्रेष्ठ-धनवत अप्रमादाचे रक्षण करतात ॥",
  "27": "प्रमादात कार्यरत असू नका, काम-रतीच्या संसर्गात राहू नका, अप्रमादी ध्यानमग्न विपुल सुख मिळवितो ।",
  "28": "जेव्हा ज्ञानी (मानव) प्रमादाला अप्रमादाने दूर घालवितो, (तेव्हा तो) प्रज्ञा-महालावर आरूढ शोकरहित (मानव) शोकग्रस्ताला (असे पाहतो, जसे) पर्वतावर उभा ज्ञानी (माणूस) जमिनीवरच्या अज्ञानी (माणसा)ला पाहतो ॥",
  "29": "अप्रमादी प्रमाद्याच्या, सदाजागृत झोपलेल्याच्या, (असा पुढे जातो, जसा) वेगवान (घोडा) अशक्ताच्या पुढे जातो ।",
  "30": "अप्रमादाने इंद्र देवतांमध्ये श्रेष्ठ झाला, (म्हणूनच) अप्रमाद्याची प्रशंसा होते, प्रमाद्याची निंदा होते ॥",
  "31": "प्रमादास घाबरणारा, अप्रमादी भिक्षू लहान-मोठ्या बंधनांना अग्नीसारखे जाळतो ।",
  "32": "प्रमादास घाबरणाऱ्या, अप्रमादी भिक्षूची हानी होणे अशक्य, (तो) निर्वाणाच्या जवळ आहे ॥",
  "chap3": "चित्तवग्गो",
  "33": "स्पंदनकारी, चपळ चित्त रक्षण (करण्यास) कठीण, स्थिर (करण्यास) कठीण, प्रज्ञावान ते सरळ करतो, जसे बाणकार (बाण) करतो ।",
  "34": "पाण्यातून जमिनीवर फेकलेला मासा जसा तडफडतो, भुलैयात अडकलेले चित्त (मुक्त होण्यास) तडफडते ॥",
  "35": "निग्रह-कठीण, गतिमान, तसेच स्वैराचारी चित्ताचे दमन (चित्त संयमित) करणे चांगले, संयमित चित्त सुखावह ।",
  "36": "अदृश्य, अति-तरबेज, तसेच स्वैराचारी अशा चित्ताचे, प्रज्ञावान (मानव) रक्षण करतो, संरक्षित चित्त सुखावह ॥",
  "37": "दूरगामी, एकटे राहणारे, निराकार, गुढ-आशयी, अशा चित्ताला जे संयमित ठेवतात, तेच भुलैया बंधनातून मुक्त होतात ।",
  "38": "अस्थिर चित्त (मानव) सुसिद्धान्त न जाणणारा, चंचल (मानव) प्रज्ञावान होत नाही ॥",
  "39": "स्थिर चित्त, मलरहित चित्त (असणाऱ्या), पाप-पुण्य विहीन, जागृत, (मानवास) कशाचेही भय नसते ।",
  "40": "शरीर (मातीच्या) घड्यासारखे जाणावे, तर चित्त शहरासारखे (विशाल) असावे, प्रज्ञा-हत्याराने भुलैयाशी युद्ध जिंकल्यावरही चित्त रक्षावे, अनासक्त ठेवावे ॥",
  "41": "नश्वर असे हे शरीर जमिनीवर पडेल, तुच्छ, चेतनाशून्य आणि निरर्थक ओंडक्यासारखे ।",
  "42": "शत्रू शत्रूचा वा वैरी वैऱ्याचा (जितके करणार नाही), वाईट संकल्पनायुक्त चित्त तितका दुष्प्रभाव (निर्माण) करते ॥",
  "43": "माता-पिता वा इतर नातेवाईक (जितके करणार नाहीत), सुसंकल्पनायुक्त चित्त तितका श्रेष्ठभाव (निर्माण) करते ।",
  "chap4": "पुप्फवग्गो",
  "44": "यमलोक आणि पृथ्वीला देवलोकांसह कोण जिंकेल? कोण चतुर या सिद्धांतांना (धम्मपदांना) फुलांसारखे सुंदर तयार करील?",
  "45": "(प्रज्ञेचा) शिष्य यमलोक आणि पृथ्वीला देवलोकांसह जिंकेल, (प्रज्ञेचा) चतुर शिष्य या सिद्धांतांना फुलांसारखे सुंदर तयार करील ॥",
  "46": "शरीर हे फेसासारखे, मृगजळासारखे समजून, पूर्ण ज्ञानी व्हावे, भुलैयाला फुलासारखे तोडून, मृत्यूस अदृश्य व्हावे ।",
  "47": "फुले वेचण्यात मनस्वी मग्न मानवास, झोपलेल्या गावाला नदी-पुराने (वाहून न्यावे), मृत्यू तसे घेऊन जातो ॥",
  "48": "फुले वेचण्यात मनस्वी मग्न मानवास, वासनांच्या अतृप्तीतच अंत (मृत्यू) वश करतो ।",
  "49": "जसे भ्रमर फुलाच्या रंग-गंधाला त्रास न देता, रस घेऊन जातो, तसे मुनीने (सुजनाने) गावात वावरावे ॥",
  "50": "दुसऱ्यांच्या विरोधात, दुसऱ्यांचे कृत्य-अकृत्य न पाहता (फक्त) स्वतःचे कृत्य-अकृत्य पहावे ।",
  "51": "जसे सुंदर रंगीत फूल सुगन्धाविना (व्यर्थ) असते, तसे कृतीविना गोड बोलणे व्यर्थ होते ॥",
  "52": "जसे सुंदर, रंगीत फूल सुगन्धामुळे (सार्थ) होते, तसे सत्कृत्यामुळे गोड बोलणे सार्थ होते ।",
  "53": "जसे फुलांच्या राशींमधून अनेक माळा करतात, तसे जन्मलेल्या मर्त्याने (मानवाने) अनेक सत्कृत्ये करावी ॥",
  "54": "चन्दन अथवा तगर-चमेली फुलांचा गन्ध वारा-विरोधी (दिशेने वाहत) नसतो, जागृत सुजनांचा गंध वारा-विरोधी (दिशेने वाहतो), सर्व दिशांना पसरतो ।",
  "55": "चन्दन, तगर-चमेली अथवा कमळाच्या गन्धाहून, सुशीलाचा (चांगल्या शीलाचा) सुगंध श्रेष्ठ आहे ॥",
  "56": "तगर-चन्दनाचा हा गन्ध अत्यल्प आहे, (परंतु) हा शीलवान माणसाचा गन्ध महाजनांपर्यंत (देवांपर्यंत) जातो ।",
  "57": "त्या शील-संपन्न, अप्रमादात राहणाऱ्या, योग्य ज्ञानामुळे मुक्त (मानवाचा) मार्ग भुलैया अडवीत नाही ॥",
  "58": "जसे महामार्गावर टाकलेल्या कचऱ्यातून, मनोहर-सुगन्धी कमळ उगवते ।",
  "59": "तसेच कचऱ्यासमान, (अज्ञानाने) आंधळ्यासारख्या सामान्य जनांत, सम्यक-सम्बुद्धाचे शिष्य प्रज्ञेने खूप चमकतात ॥",
  "chap5": "बालवग्गो",
  "60": "जागणऱ्याची रात्र लांबत जाते, थकलेल्याचा मैल (रस्ता) लांबत जातो, सदाचार न जाणणाऱ्या अज्ञानीचा संसार (जीवन प्रवाह) लांबत जातो ।",
  "61": "चालताना स्वतःसारखा किंवा स्वतःहून श्रेष्ठ (सोबती) न लाभल्यास, खंबीरपणे एकाकी चालावे, अज्ञानीची सोबत करू नये ॥",
  "62": "माझा पुत्र, माझी संपत्ती, असे अज्ञानी दुक्खी होतात, स्वतःच स्वतःचा नसतो, (तर) कसा पुत्र, कशी संपत्ती ।",
  "63": "अज्ञानी स्वतःला अज्ञानी समजत असेल तर तो तितका ज्ञानी आहे, अज्ञानी असूनही स्वतःला बुद्धिमान सांगतो तो (खरा) अज्ञानी ॥",
  "64": "अज्ञानी (मानव) जीवनभर बुद्धिमंताच्या सोबत राहिला तरी त्याला सुसिद्धांत (धम्म) समजत नाही, जसे पळीला वरणाचा स्वाद ।",
  "65": "सुजाण माणूस क्षणभरही बुद्धिमंताच्या सोबत राहिला तरी त्याला सुसिद्धांत (धम्म) समजतो, जसे जिभेला वरणाचा स्वाद ॥",
  "66": "अज्ञानी, दुर्बुद्ध स्वतःच स्वतःचा शत्रू होतो, दुष्कृत्य करून, ज्याची फळे कडू असतात ।",
  "67": "ते कृत्य करणे चांगले नाही, ज्याने पश्चात्ताप करावा लागतो, आणि ज्याचे परिणाम अश्रू(पूर्ण) चेहऱ्याने रडत भोगावे लागतात ॥",
  "68": "ते कृत्य करणे चांगले, ज्याने पश्चात्ताप करावा लागत नाही, आणि ज्याचे परिणाम प्रसन्न चित्ताने, चांगल्या मनाने भोगता येतात ।",
  "69": "जोवर दुष्कृत्य पक्व होत नाही तोवर अज्ञानी त्याला गोड समजतात, जेव्हा दुष्कृत्य परिपक्व (परिणामित) होते, तेव्हा ते दुक्खी होतात ॥",
  "70": "अज्ञानी (माणसाने) महिनो-महिने गवताच्या टोकाने अन्न खाल्ले, तरी तो सुसिद्धांत जाणणाऱ्याच्या सोळाव्या भागाच्या समतुल्य होत नाही ।",
  "71": "वाईट केलेली कृत्ये (ताज्या) दुधासारखी त्वरित नासत (परिणामित होत) नाहीत, ती राखेने आच्छादित निखाऱ्यांसारखी, अज्ञानी (मानवा)चा पाठलाग करतात ॥",
  "72": "अज्ञानीच्या जाणिवांचा आभाळापर्यंत अनर्थ होतो, अज्ञानीच्या शुभकृत्यांचा नाश होतो, शिराचा (बुद्धीचा) नाश होतो ।",
  "73": "भिक्षूंमध्ये आदर प्राप्तीची इच्छा, (हे) दुष्टतेचे, चुकीचे आहे. मठ-मंदिराचा उपभोग, परक्या कुळाच्या (लोकां) कडून पूजिले जाणे ॥",
  "74": "गृहस्थ व प्रवज्जित या दोहोत माझ्यासारखा कोण? योग्य-अयोग्य कार्यांवर माझेच स्वामित्व असावे, अशी संकल्पना करणाऱ्या अज्ञानीच्या आकांक्षा, गर्व वाढतो ।",
  "75": "लाभाचा मार्ग वेगळा, निर्वाणाचा मार्ग वेगळा, हे असे जाणून बुद्धाच्या शिष्य भिक्षूने, सत्काराने आनंदू नये, विवेकाची वृद्धी करावी ॥",
  "chap6": "पण्डितवग्गो",
  "76": "जो दोषाची बाजू दाखविणाऱ्याला संपत्तीच्या अस्तित्वासम समजतो, (मनो)निग्रही, प्रज्ञावान, बुद्धिवानासारख्यांची संगत करतो, तशा चित्ताच्या संगाने श्रेष्ठ (भले) होते, वाईट होत नाही ।",
  "77": "जो उपदेश करतो, अनुशासन करतो, अनुचिताचे (अन् उचिताचे) निवारण करतो, ते सुजनांना प्रिय असतात, दुर्जनांना अप्रिय असतात ॥",
  "78": "दुराचारी मित्राची संगत नको, अधम माणसाची संगत नको, कल्याणकारी मित्राची संगत करावी, उत्तम माणसाची संगत करावी ।",
  "79": "सदाचारावर श्रद्धा (प्रीती) असणारा सुखाने, निश्चिंत मनाने झोपतो. बुद्धिमान (आर्यांनी) सुजनांनी सांगितलेल्या सिद्धांतात रममाण असतात ॥",
  "80": "(पाणी) नेणारा पाणी नेतो, बाणकार बाण बनवितो, सुतार लाकूड बनवितो, बुद्धिमान स्वतःला कष्टवितात ।",
  "81": "जसे मोठा पर्वत वाऱ्याने हलत नाही, तसेच बुद्धिमंत निंदा वा प्रशंसेने विचलित होत नाहीत ॥",
  "82": "जसे अथांग, स्थिर तलाव नितळ-स्वच्छ असतात, तसे बुद्धिमंत 'सदाचार सिद्धांत' (धम्म) ऐकून नितळ (स्पष्ट) होतात ।",
  "83": "सत्पुरुष सर्वस्व त्यागतात, सुजन इच्छा-भोगा संबंधी बोलतही नाहीत, सुखाने वा दुक्खाने ग्रासले तरी बुद्धिमंत उच्च-नीचता पहात (विकृत होत) नाहीत ॥",
  "84": "(ज्याच्या मनी) ना स्वतःसाठी, ना दुसऱ्यासाठी, ना पुत्राच्या इच्छेसाठी, ना राज्यासाठी, ना स्वतःच्या समृद्धीसाठी, दुराचाराची (अधर्माची) इच्छा, तोच शीलवान, प्रज्ञावान, सदाचारी (धम्मिक) होतो ।",
  "85": "जे लोक पार जातात ते मानवात कमीच, तेव्हा इतर प्रजा (लोक) किनाऱ्यावरच धावत असतात ॥",
  "86": "काळा (वाईट) स्वभाव सोडून बुद्धिमानांनी शुभ-सवय करावी, घरातून बेघर (होऊन), विचाराने दूर जाऊन (एकाकी व्हावे) ।",
  "87": "वासनांचा त्याग करून, तेथेच राहण्याची इच्छा करावी, स्वतःच्या चित्ततले क्लेश स्वच्छ करावे ॥",
  "88": "ज्यांचे चित्त सर्वांगाने सुबुद्ध, योग्य असते, विचार न करता (निश्चयाने) ग्रहणाच्या परित्यागात रममाण असतात, वाईट-विचार-क्षीण, प्रभावंत (मानव) (या) लोकात निर्वाण प्राप्त करतात ।",
  "89": "ज्यांचे चित्त सात बोध्यंगांच्या अभ्यासाने सुविकसित आहे, जे सर्व प्रकारच्या आसक्तीचा त्याग करून अनासक्त राहण्यात आनंद मानतात, ज्यांचे विकार क्षीण झाले आहेत आणि जे तेजस्वी आहेत, ते या जगातच पूर्णपणे मुक्त (निर्वाण प्राप्त) होतात ॥",
  "chap7": "अरहन्तवग्गो",
  "90": "मार्ग समाप्त केलेला (अंताला पोचलेला), शोक-रहित, सर्वथा मुक्त, सर्व-बंधन-क्षीण (मानवास) परिताप होत नाही ।",
  "91": "विचारवंत-उद्योग करतात, घरात (सामान्य गोष्टीत) रमत नाहीत, जसा हंस लहान तलाव सोडून जातो, तसेच घरातले 'घर' सोडून जातात ॥",
  "92": "जे संचय करीत नाहीत, जे भोजनाची योग्य मात्रा जाणतात, शून्य-स्वरूप, निमित्त-रहित विमुक्ती ज्याच्या दृष्टीपथात आहे, त्यांची गती, आकाशात पक्षांची असते तशी, अज्ञेय असते ।",
  "93": "ज्याचे वाईट विचार क्षीण आहेत, आहारात आसक्त नाही, शून्य-स्वरूप, निमित्त-रहित विमुक्ती ज्याच्या दृष्टीपथात आहे, त्यांचे स्थान, आकाशात पक्षांचे असते तसे, अज्ञेय असते ॥",
  "94": "ज्याचे इंद्रिय शांत आहेत, जसा सारथ्याने सुशिक्षित (केलेला) घोडा, अहंकार त्यागलेले, दुविचारविहीन (मानव), महाजनांनाही प्रिय होतात ।",
  "95": "जो सदाचारात पृथ्वीसारखा, नगर-द्वार-स्तंभासम निश्चल असतो, त्याच्यात जगरहाटीचे अस्तित्व राहत नाही, जसे शेवाळ दूर केलेला तलाव ॥",
  "96": "शीणलेले मन, वाचा, कृती शांत होतात. सुजाणतेमुळे विमुक्त होऊन, तसे चित्त शांत होते ।",
  "97": "अश्रद्धा, अकृतज्ञता यांच्याशी संबंध छेदणारा मानव, शुभ-अशुभाच्या मर्यादा त्यागलेला, तो उत्तम मानव ॥",
  "98": "गाव किंवा रान (जंगल), तळ (खोल जमीन) किंवा पठार (सपाट जमीन), जेथे अर्हत राहतात, ती भूमी रमणीय (आनंददायी) ।",
  "99": "जेथे (सामान्य) लोक रममाण होत नाहीत, तेथे अरण्यात सुजन रमतात, तेथे वैरागी रमतात, कारण ते भोगाचा शोध घेत नाहीत ॥",
  "chap8": "सहस्सवग्गो",
  "100": "हजारो निरर्थक पदांची गाथा बोलण्या (वाचण्या) पेक्षा, एक अर्थपूर्ण पद श्रेष्ठ, जे ऐकून शांती मिळते ।",
  "101": "हजारो गाथा, निरर्थक पदांनी बनलेल्या, पेक्षा एक अर्थपूर्ण गाथा श्रेष्ठ, जी ऐकून शांती मिळते ।",
  "102": "शंभर निरर्थक पदांनी बनलेल्या गाथा सांगण्यापेक्षा एक सदाचार-पद श्रेष्ठ, जे ऐकून शांती मिळते ॥",
  "103": "जो युद्धात लाखो लोकांना जिंकतो (त्या जेत्याहून), जो एक स्वतःला जिंकतो, तो उत्तम युद्धजेता होय ।",
  "104": "इतर (प्रजा)जनांपेक्षा स्वतःचा निश्चयाने विजय श्रेष्ठ, स्वतःला स्वतःच्या ताब्यात ठेवणे, नित्य संयमित आचारांचे पोषण (असा विजय) ॥",
  "105": "ना महाजन, ना गंधर्व, ना भुलैयासह ब्रह्मा, ना अशा प्रकारचा कोणीही जीव, या विजयाचा पराजय करील ।",
  "106": "महिनोंमहिने हजार यज्ञ, शंभर वर्षांपर्यंत पुन्हा-पुन्हा, आणि एकच विशेष-ज्ञानीचा (प्रज्ञावानाचा) क्षणभराचा सत्कार (पूजा), हे पूजन श्रेष्ठ होते, शतवर्ष केलेल्या (वरील यज्ञा) पेक्षा ॥",
  "107": "शतवर्ष, वनात विहरणाऱ्या जीवांना अग्नीत (आहुती), आणि एकच विशेष-ज्ञानीचा (प्रज्ञावानाचा) क्षणभराचा सत्कार (पूजा), हे पूजन श्रेष्ठ होते, शतवर्ष केलेल्या (वरील यज्ञा) पेक्षा ।",
  "108": "या लोकात पुण्याच्या अपेक्षेने वर्षभर यज्ञ (करणे), काही आहुती (देणे), हे सर्व उज्ज्वल-श्रेष्ठाला अभिवादन करण्याच्या चौथ्या भागाइतकेही नाही ॥",
  "109": "अभिवादनशील, नित्य ज्येष्ठांची सेवा करणाऱ्यांचे, आयुष्य, वर्ण (सौंदर्य), सुख, बळ हे चारही स्वभाव वाढतात ।",
  "110": "शीलहीन, एकाग्रचित्तहीन (मानवाच्या) शंभर वर्ष आयुष्याहून, शीलवान-ध्यानी (मानवाचा) एक दिवस श्रेष्ठ असतो ॥",
  "111": "प्रज्ञाहीन, एकाग्रचित्तहीन (मानवाच्या) शंभर वर्ष आयुष्याहून, प्रज्ञावान-ध्यानी (मानवाचा) एक दिवस श्रेष्ठ असतो ।",
  "112": "आळशी, शौर्यहीन (मानवाच्या) शंभर वर्ष आयुष्याहून, दृढ-उद्योगी, शूर (मानवाचा) एक दिवस श्रेष्ठ असतो ॥",
  "113": "उत्पत्ती-विनाश न पाहणाऱ्या (मानवाच्या) शंभर वर्ष आयुष्याहून, उत्पत्ती-विनाश पाहणाऱ्या (मानवाचा) एक दिवस श्रेष्ठ असतो ।",
  "114": "अमृतपद (निर्वाण) न पाहणाऱ्या (मानवाच्या) शंभर वर्ष आयुष्याहून, अमृतपद पाहणाऱ्या (मानवाचा) एक दिवस श्रेष्ठ असतो ॥",
  "115": "उत्तम जीवन सिद्धांत न पाहणाऱ्या (मानवाच्या) शंभर वर्ष आयुष्याहून, उत्तम जीवन सिद्धांत पाहणाऱ्या (मानवाचा) एक दिवस श्रेष्ठ असतो ।",
  "chap9": "पापवग्गो",
  "116": "सत्कार्य त्वरेने करावे, चित्त दुष्कृत्यापासून दूर करावे, सत्कार्य करण्यात शिथिलता आल्यास मन दुष्कृत्यात रमते ॥",
  "117": "मनुष्याने (एकदा) दुष्कृत्य केले, तर ते पुन्हा-पुन्हा करू नये, ती इच्छा करू नये, दुष्कृत्याच्या संग्रहाने दुक्ख वाढते ।",
  "118": "मनुष्याने (एकदा) सत्कृत्य केले, तर ते पुन्हा-पुन्हा करावे, तशी इच्छा करावी, सत्कृत्याच्या संग्रहाने सुख वाढते ॥",
  "119": "दुष्कृत्य करणाऱ्याला भले वाटते, जोवर दुष्कृत्य पक्व (फलदायी) होत नाही, जेव्हा दुष्कृत्य पक्व (फलदायी) होते, तेव्हा त्याला ते वाईट वाटते ।",
  "120": "सत्कृत्य करणाऱ्याला वाईट वाटते, जोवर सत्कृत्य पक्व (फलदायी) होत नाही, जेव्हा सत्कृत्य पक्व (फलदायी) होते, तेव्हा त्याला ते चांगले वाटते ॥",
  "121": "माझ्या जवळ दुष्कृत्य येणार नाही असा गर्व करू नये, पाण्याच्या थेंबांनीच पाण्याचा घडा भरतो, अज्ञानी थोडे-थोडे दुष्कृत्य करून पूर्ण साठवतो ।",
  "122": "माझ्या जवळ सत्कृत्य येणार नाही असा गर्व करू नये, पाण्याच्या थेंबांनीच पाण्याचा घडा भरतो, बुद्धिमान थोडे-थोडे सत्कृत्य करून पूर्ण साठवतो ॥",
  "123": "व्यापारी, खूप धनवान, भयावह मार्गाची अप्रशंसा करतात, जिगीषा असणारे विषाची, तशीच (मानवाने) दुष्कृत्याची (अप्रशंसा) करावी ।",
  "124": "हाताला जखम नसेल तर हातात विष घेता येईल, जखम-रहिताला विष बाधत नाही, तसे न कर्त्याला दुष्कृत्य (बाधत नाही) ॥",
  "125": "जो शुद्ध, दोषरहित, पोषित माणसाचा द्वेष करतो, काही दृष्टता करतो, तो अज्ञानीच वाईट होतो, जसे वाऱ्याच्या विरुद्ध फेकलेली सूक्ष्म धूळ (फेकणाऱ्यावरच पडते) ।",
  "126": "काही गर्भात जन्मतात, दुष्कर्मी नरकात जातात, सन्मार्गी स्वर्गात जातात, सत्चित्त निर्वाण-प्राप्त होतात ॥",
  "127": "न अंतरिक्षी, न समुद्रात, न पर्वतावर, न विवरात शिरून, जगात असा प्रदेश विद्यमान नाही, जेथे राहून (मानव) दुष्कृत्य-परिणाम मुक्त राहील ।",
  "128": "न अंतरिक्षी, न समुद्रात, न पर्वतावर, न विवरात शिरून, जगात असा प्रदेश विद्यमान नाही, जेथे राहून (मानव) मृत्यूमुक्त राहील ॥",
  "chap10": "दण्डवग्गो",
  "129": "शिक्षेला सर्वच घाबरतात, मृत्यूला सारेच भितात, सर्वांना स्वतःसारखेच समजावे, मारू नये, वध करू नये ।",
  "130": "शिक्षेला सर्वच घाबरतात, साऱ्यांना जीव प्रिय असतो, सर्वांना स्वतःसारखेच समजावे, मारू नये, वध करू नये ॥",
  "131": "सुख इच्छिणाऱ्या प्राण्यांना काठीने (शस्त्राने) मारतो, त्या सुखाची इच्छा असणाऱ्या मानवाला मरणोत्तरही सुख लाभत नाही ।",
  "132": "सुख इच्छिणाऱ्या प्राण्यांना काठीने मारीत नाही, त्या सुखाची इच्छा असणाऱ्या मानवाला मरणोत्तरही सुख लाभते ॥",
  "133": "कधीही कठोर बोलू नये, त्याचे तसेच प्रत्युत्तर मिळते, कठोर बोलणे दुक्खदायक असते, त्याने तुम्हास दंडाचेच प्रत्युत्तर मिळते ।",
  "134": "तुम्हास इजा झाली तरी काश्यासम (धातू) अचूक राहिल्यास तुम्हास निर्वाण प्राप्त झाले आहे, काहीही विवाद राहिलेला नाही ॥",
  "135": "जसे गोपाल गाईंना काठीने हाकलून रानात नेतात, तसे वार्धक्य आणि मृत्यू प्राण्यांचे आयुष्य नेतात ।",
  "136": "दुष्कर्म करणाऱ्या अजाणास काहीच समजत नाही, पण याच कर्माने दुर्बुद्ध अग्नीत जाळल्यासारखे तप्त होतो ॥",
  "137": "जो काठीविरहितास (निःशस्त्रास) काठीने (शस्त्राने), दोषरहितास दोषाने त्रासतो, त्याच्या ठायी या दहापैकी एक (वेदना) त्वरित निर्माण होते ।",
  "138": "कठोर वेदना, हानी, शरीर भेदन, गंभीर आजार जडणे, मनोविकाराची प्राप्ती ॥",
  "139": "राजाकडून शिक्षा, तीव्र खोटे आरोप, नातेवाईकांचा विनाश, संपत्तीचा विनाश ।",
  "140": "त्याच्या घराला आग जाळून टाकते, अशा दुर्बुद्धाचा शरीर-नाशानंतर नरकात पुनर्जन्म होतो ॥",
  "141": "न नग्न राहून, ना जटा वा चिखल धारण करून, न निराहार राहून, ना कडक जमिनीवर झोपून, ना धूळ माखून, ना उकिडवे बसून मानवाची शुद्धी होते; ज्याचे मन शुद्ध नाही, त्या मानवाची शुद्धी होत नाही ।",
  "142": "अलंकार लेऊनही ज्याचे आचरण योग्य आहे, जो शांत, संयमी आणि ब्रह्मचारी आहे, ज्याने सर्व प्राण्यांना त्रास देणे त्यागले आहे, तोच ब्राह्मण, तोच श्रमण, तोच भिक्खू ॥",
  "143": "लोकात काही मानव असे असतात, ज्यांना स्वतःची लाज (दुष्कृत्यांपासून) रोखते, त्यांना निंदा असह्य असते जसा घोड्याला चाबूक ।",
  "144": "जसा घोडा चाबकामुळे सरळ असतो, तसे वेगवान, तत्पर व्हावे; श्रद्धा, शील, वीर्य, एकाग्रता, सदाचार निश्चय यांनी युक्त व्हावे; विद्या व आचरणाने संपन्न, विचारवंत व्हावे, आणि मोठ्या दुक्खाचा नाश करावा ॥",
  "145": "(पाणी) नेणारा पाणी नेतो, बाणकार बाण बनवितो, सुतार लाकूड बनवितो, सुवृत्त (मानव) स्वतःला कष्टवितात ।",
  "chap11": "जरावग्गो",
  "146": "कसे हसणे? काय आनंद? जाणिवा नित्य जळत आहेत, अंधाराने वेढलेल्या मानवा, प्रदीपाचा शोध का घेत नाहीस? ॥",
  "147": "जखमांनी सुजलेल्या, व्रणांनी सजलेल्या या शरीराचे चित्र पहा, रोग आणि नाना संकल्पांनी युक्त, याचे निश्चित स्थान नाही ।",
  "148": "अतिशय जुने झालेले हे शरीर, रोग-स्थान आहे, क्षणभंगुर आहे, सडून भग्न होणार आहे. सगळे जीव मरणारच ॥",
  "149": "शरदकाळी अपथ्य असणाऱ्या भोपळ्यासारखे (हे शरीर), (शुभ्र) कबुतरासारखी पांढरी हाडे, हे पाहून काय आसक्ती व्हावी? ।",
  "150": "(हे शरीर) हाडांचे वास्तव्य, त्यावर रक्ता-मांसाचे लेपन केले आहे, त्यात वृद्धत्व, मृत्यू, गर्व, द्वेष लपविलेला आहे ॥",
  "151": "सुंदर रंगविलेला (सुचित्रित) राजरथ जुना होतो, असेच शरीर म्हातारे होते, जागृत जीवन-सिद्धांत (धम्म) जीर्ण होत नाही, असे सुजन विज्ञापित करतात ।",
  "152": "थोडेसेच ऐकलेला (अज्ञानी) मानव, बैलासारखा मांसाने वाढतो, म्हातारा होतो, त्याचे ज्ञान वाढत नाही ॥",
  "153": "अनेक जन्म विश्रांतीविना सतत फिरतो आहे, या घराच्या निर्मात्याला शोधीत, पुन्हा-पुन्हा जन्मवेदना (आहे) ।",
  "154": "घराच्या निर्मात्या! तू मला दिसलास. तू पुन्हा घर करणार नाहीस, सगळ्या बरगड्या मोडल्या आहेत, छप्पर नष्ट पावले आहे, मन निःशंक झाले आहे, लालसांचा क्षय झाला आहे ॥",
  "155": "ब्रह्मचर्य आचरले नाही, तारुण्यात धन प्राप्ती केली नाही, ते बिन माशांच्या तलावात म्हाताऱ्या करकोच्यासारखे ध्यान लावतात ।",
  "156": "ब्रह्मचर्य आचरले नाही, तारुण्यात धन प्राप्ती केली नाही, ते जुन्या धनुष्य-बाणासारखे पश्चात्ताप करतात ॥",
  "chap12": "अत्तवग्गो",
  "157": "जर स्वतःवर प्रेम करत असाल, स्वतःला श्रेष्ठ संरक्षित करा, बुद्धिमंत रात्रीच्या तीन प्रहरातला एक प्रहर जागृत असतात ।",
  "158": "जे योग्य आहे ते प्रथम स्वतः करावे, नंतर इतरांना सांगावे, म्हणजे बुद्धिमंतांना डाग लागणार नाही ॥",
  "159": "इतरांना जसे सांगतो तसेच स्वतः करतो, तो इतरांना संयमित करतो. वास्तविक स्वतःला संयमित करणे कठीण आहे ।",
  "160": "स्वतःच स्वतःचा स्वामी असतो, दुसरा कोण स्वामी असतो? स्वतःला संयमित करणाऱ्यास दुर्लभ स्वामित्वाचा लाभ होतो ॥",
  "161": "स्वतः केलेले, स्वतः जन्म दिलेले, स्वतःतून निर्माण झालेले दुष्कर्म, दुर्बुद्धाला असे तोड-फोडते जसे वज्र दगडात रुतलेल्या मण्याला ।",
  "162": "ज्याचा दुराचार शाल वृक्षावर पसरलेल्या वेलीसारखा पसरला आहे, तो तसेच करतो जसे शत्रू इच्छितो ॥",
  "163": "अमंगल, स्वतःला आहतकारी कृत्य करणे सोपे असते; मंगल, स्वतःला हितकारी कृत्य करणे खूप कठीण असते ।",
  "164": "जी शिकवण योग्य-सुजनांची, जीवन-सिद्धांत यांची, या शिकवणीची निंदा करणाऱ्या दुर्बुद्धाचा असा नाश होतो, जसे बांबूचे फळ स्वनाशासाठीच परिपक्व होते ॥",
  "165": "स्वतः केलेले दुष्कर्म स्वतःला कलुषित करते, स्वतः न केलेले दुष्कर्म स्वतःला शुद्ध ठेवते; प्रत्येकाची शुद्धी-अशुद्धी वेग-वेगळी असते, कोणीही दुसरा दुसऱ्याला शुद्ध करीत नाही ।",
  "166": "परोपकारासाठी स्वार्थाची खूप उपेक्षा करू नये, स्वार्थाला नीट समजून घेऊन आत्मकल्याण पहावे ॥",
  "chap13": "लोकवग्गो",
  "167": "हीन कृत्य करू नये, बेपर्वा राहू नये, वाईट दृष्टी ठेवू नये, लोक-वृद्धी (जन्म वृद्धीची अपेक्षा) बाळगू नये ।",
  "168": "उठा, अजागृत राहू नका, सैद्धांतिक (धम्माप्रमाणे) जीवन जगा, सदाचाराने राहणारे येथे आणि परलोकातही सुखात राहतात ॥",
  "169": "सैद्धांतिक (धम्माप्रमाणे) जीवन जगा, दुर्गुणांनी राहू नका, सदाचाराने राहणारे येथे आणि परलोकातही सुखात राहतात ।",
  "170": "जसे बुडबुड्याकडे पहावे, जसे मृगजळाकडे पहावे, तसे निरीच्छपणे जो जीवनाकडे पाहतो, त्याच्याकडे मृत्युराजा पाहत नाही ॥",
  "171": "चित्रासारख्या (सुंदर) राजरथाप्रमाणे या जगाला पहा, इथे अज्ञानी धडपडतात, सुज्ञान आसक्त होत नाहीत ।",
  "172": "जे आधी बेपर्वा असतात, जाणवल्यानंतर बेपर्वा असत नाहीत, ते ढग बाजूला झालेल्या चंद्रासारखे या जगात प्रकाशित होतात ॥",
  "173": "जे केलेल्या दुष्कृत्यांना सत्कृत्यांनी झाकून टाकतात, ते ढग बाजूला झालेल्या चंद्रासारखे या जगात प्रकाशित होतात ।",
  "174": "हे जग अंध आहे, इथे थोडेच पाहतात, जाळ्यातून सुटलेल्या पक्षांसारखे थोडेच लोक स्वर्गात (सुखाकडे) जातात ॥",
  "175": "हंस सूर्यपथावर (आकाशात) जातात, ऋद्धीप्राप्त आकाशातून जातात, सेनेसह आलेल्या भुलैयाला जिंकतात, ते या लोकातून निघून जातात ।",
  "176": "जो एका (सत्य) सदाचाराला पार करतो, जो खोटे बोलणारा जीव आहे, ज्याने परलोक तुच्छिला आहे, तो करणार नाही असे दुष्कृत्य नाही ॥",
  "177": "कंजूस महाजन-लोकी जात नाहीत, अज्ञानी दानाची प्रशंसा करीत नाहीत, बुद्धिवान दानाचे अनुमोदन करतात, त्यामुळे परलोकात सुखी होतात ।",
  "178": "एकट्याने पृथ्वीचा राजा होण्यापेक्षा, स्वर्गात जाण्यापेक्षा, सर्व लोकांचा अधिपती होण्यापेक्षा, श्रेष्ठ आहे सैद्धांतिक जीवनपथाचे फळ ॥",
  "chap14": "बुद्धवग्गो",
  "179": "ज्याच्या जयाचा अविजय होणार नाही, ज्याच्या जयापर्यंत या लोकांतील कोणीही जाणार नाही, त्या विस्तीर्ण हिरवळरूपी निष्कलंक बुद्धांना तुम्ही आपल्या जीवनात कोणत्या मार्गाने न्याल? ।",
  "180": "ज्याला विषाचे जाळे पसरविणारी तृष्णा कोठेही नेऊ शकत नाही, त्या विस्तीर्ण हिरवळरूपी निष्कलंक बुद्धांना तुम्ही आपल्या जीवनात कोणत्या मार्गाने न्याल? ॥",
  "181": "जो ध्यानस्थ, ज्ञानी, संसारसुख त्यागूनही संतुष्ट आहे, त्या स्मृतिवान सम्बुद्धावर देव प्रेम करतात ।",
  "182": "मानव जीवन प्राप्त होणे अवघड, मर्त्य जीवन जगणे अवघड, उत्तम धम्म ऐकणे अवघड, बुद्धांचे उत्पन्न होणे अवघड ॥",
  "183": "सर्व पापे न करणे, सत्कृत्याचा अवलंब करणे, चित्त शुद्ध करणे, हाच बुद्धांचा सिद्धांत । (हीच बुद्धांची शिकवण.)",
  "184": "बुद्ध सांगतात, शांती आणि सहनशीलता अत्युच्च साधना आहे, निर्वाण अत्युच्च आहे; पर-घात करणारा प्रवज्जित होत नाही, दुसऱ्यांना त्रासविणारा श्रमण होत नाही ॥",
  "185": "निंदा न करणे, घात न करणे, भिक्खू नियमांचे पालन करणे, माफक भोजन, एकांतात शयन-आसन, एकाग्र-चित्ताचा प्रयत्न, हाच बुद्धांचा सिद्धांत ।",
  "186": "सोन्या-नाण्यांच्या वर्षावानेही इच्छांची तृप्ती होत नाही, काम-भोग अल्पस्वादी-वेदनादायी आहेत हे ज्ञानीजन जाणतात ॥",
  "187": "परंतु ज्ञानीजन दिव्य काम-भोगातही आसक्ती प्राप्त करीत नाहीत. सम्यक-सम्बुद्धांचे शिष्य तृष्णा-नाशात मग्न राहतात ।",
  "188": "अनेक जण पर्वत, वन इत्यादींना शरण जातात, तसेच भयभीत होऊन उद्यान, वृक्ष, चैत्य इत्यादींनाही शरण जातात ॥",
  "189": "हे शरण जाणे कल्याणकारी नाही, हे शरण जाणे उत्तम नाही, हे शरण जाणे सर्व वेदनांचे उच्चाटन करणारे नाही ।",
  "190": "जो बुद्ध, धम्म आणि संघ अनुसरण करतो, सम्यक प्रज्ञेने चार आर्यसत्यांचे आकलन करतो ॥",
  "191": "वेदना, वेदनेचे कारण, वेदनेचे निवारण, वेदना निवारणाचा आर्य अष्टांग मार्ग (आकलन करतो), ।",
  "192": "हेच त्याचे कल्याणकारी अनुसरण, उत्तम अनुसरण, याच अनुसरणाने सर्व वेदनांचे उच्चाटन होते ॥",
  "193": "मानव जीवन दुर्लभ, ते सर्वांना प्राप्त होत नाही; ज्याला ते प्राप्त होते, त्या ज्ञानी मानवाच्या कुळाचे सुख वाढते ।",
  "194": "बुद्धांचे अस्तित्व सुखकारक, सद्धम्माचा उपदेश सुखकारक, एकत्रित सुजनांचे (संघाचे) एकत्व सुखकारक, एकत्रित साधना सुखकारक ॥",
  "195": "पूजनीय बुद्ध व त्यांचे शिष्य, जे प्रपंचाच्या आणि शोकाच्या पल्याड गेले आहेत, ।",
  "196": "अशा शांत, निर्भय (बुद्ध व त्यांचे शिष्य) यांच्या पूजनाचे पावित्र्य 'फक्त इतके' असे सांगणे कोणासही शक्य नाही ॥",
  "chap15": "सुखवग्गो",
  "197": "निश्चित सुखी आहोत! वैर करणाऱ्यांत अवैरी राहून, वैरी माणसांत आम्ही अवैरी विहार करतो ।",
  "198": "निश्चित सुखी आहोत! रोगी जीवांमध्ये निरोगी राहून, रोगी माणसांत आम्ही निरोगी विहार करतो ॥",
  "199": "निश्चित सुखी आहोत! आसक्त माणसांत अनासक्त राहून, आसक्त माणसांत आम्ही अनासक्त विहार करतो ।",
  "200": "निश्चित सुखी आहोत! आम्हा जवळ काहीच नाही, प्रियदर्शी महाजनांसारखे, प्रेम हेच आमचे भोजन आहे ॥",
  "201": "विजयाने वैर निर्माण होते, पराजित दुक्खात राहतो, शांतचित्त (मानव) जय-पराजय सोडून सुखाने झोपतो ॥",
  "202": "आसक्तीसारखा अग्नी नाही, द्वेषासारखा पराजय नाही, (पाच) स्कंधांसारखे दुक्ख नाही, शांतीसारखे सुख नाही ।",
  "203": "भूक हा मोठा रोग आहे, संस्कार (भौतिकता) हे मोठे दुक्ख आहे; या यथार्थाला जो जाणतो, त्याच्यासाठी निर्वाण हे मोठे सुख आहे ॥",
  "204": "निरोगी असणे खूप लाभदायक, संतुष्टी ही श्रेष्ठ संपदा, विश्वास हा चांगला नातेवाईक, निर्वाण हे श्रेष्ठ सुख ।",
  "205": "एकान्तवासाचे व शांतीचे रसपान केल्याने (मानव) निर्भय होतो, सदाचार रसपानाने निष्पाप होतो ॥",
  "206": "सज्जनांचे दर्शन चांगले, संगत सदा सुखकर; अज्ञानांचे दर्शनही न होणे नित्य सुखकर ।",
  "207": "अज्ञानींची संगती करणारा खूप काळापर्यंत पश्चात्ताप करतो; अज्ञानींची व अमित्राची (शत्रूची) संगती सदैव सारखीच दुक्खदायक, बुद्धिमानांची संगती नातेवाईकांच्या मेळ्यासारखी सुखद असते ॥",
  "208": "म्हणून बुद्धिवान, प्रज्ञावान, बहुश्रुत, शीलभार सोसणारा, व्रतस्थ सुजन आणि सुबुद्ध सज्जनांची संगत करावी, जसा चंद्र नक्षत्र मार्गाची सोबत करतो ।",
  "chap16": "पियवग्गो",
  "209": "स्वतःला अनुचित कार्यात लावणारा, उचित कार्यात न लावणारा, अर्थपूर्ण सोडून प्रियाच्या मागे जाणारा (तो फक्त) स्वार्थाची इच्छा करतो ॥",
  "210": "प्रियजनांच्या संगतीत राहू नका, अप्रियांच्या संगतीत कधीच नका; प्रियजनांचे दर्शन न होणे आणि अप्रियजनांचे दर्शन होणे दुक्खाचे असते ।",
  "211": "म्हणून काहीही प्रिय करू नका, प्रिय निघून जाणे वाईट वाटते; त्यांना बंधन नसते ज्यांना प्रिय-अप्रिय असे काही नसते ॥",
  "212": "प्रियामुळे शोक उत्पन्न होतो, प्रियामुळे भीती उत्पन्न होते; जो प्रियापासून मुक्त असतो त्याला शोक नसतो, तर भीती कशी? ।",
  "213": "प्रेमामुळे शोक उत्पन्न होतो, प्रेमामुळे भीती उत्पन्न होते; जो प्रेमापासून मुक्त असतो त्याला शोक नसतो, तर भीती कशी? ॥",
  "214": "आसक्तीमुळे शोक उत्पन्न होतो, आसक्तीमुळे भीती उत्पन्न होते; जो आसक्तीपासून मुक्त असतो त्याला शोक नसतो, तर भीती कशी? ।",
  "215": "भोगामुळे शोक उत्पन्न होतो, भोगामुळे भीती उत्पन्न होते; जो भोगापासून मुक्त असतो त्याला शोक नसतो, तर भीती कशी? ॥",
  "216": "लालसेमुळे शोक उत्पन्न होतो, लालसेमुळे भीती उत्पन्न होते; जो लालसेपासून मुक्त असतो त्याला शोक नसतो, तर भीती कशी? ।",
  "217": "जो शीलसंपन्न, दृष्टीज्ञानसंपन्न आहे, सदाचाराने सत्यवचनी आहे, स्वतःचे काम करणारा आहे, त्या मानवास लोक प्रेम करतात ॥",
  "218": "ज्याला अव्याख्याची अभिलाषा आहे आणि ज्याला मनाने स्पर्श केला आहे, जो काम-भोगात अनासक्त असतो, त्याला ऊर्ध्वगामी म्हणतात ।",
  "219": "फार पूर्वी प्रवासाला गेलेला माणूस दूरवरून सुखरूप परत येतो, तेव्हा नातेवाईक-मित्र सुहृदयाने येणाऱ्याचे अभिनंदन करतात ॥",
  "220": "याच प्रकारे सत्कर्म करणाऱ्याचे या लोकातून दुसरीकडे सत्कर्म स्वागत करतात, जसे नातेवाईक प्रिय व्यक्तीचे करतात ।",
  "chap17": "कोधवग्गो",
  "221": "क्रोधाचा त्याग करावा, अभिमानाचा त्याग करावा, सर्व बंधनांवर आक्रमक व्हावे; नाम-रूपात अनासक्त व निःशेष असावे, त्यायोगे दुक्ख मागे येत नाही ॥",
  "222": "जो उसळणाऱ्या क्रोधाला स्थिर करतो, पथभ्रष्ट रथाला जसे हुशार सारथी, त्यालाच मी सच्चा सारथी म्हणतो; इतर लोक फक्त दोरी धरणारे ।",
  "223": "अक्रोधाने क्रोधाला जिंकावे, वाईटाला उत्तमाने जिंकावे, कंजूषपणाला दानाने जिंकावे, सत्याने खोटे बोलणे जिंकावे ॥",
  "224": "सत्य बोलावे, क्रोधित होऊ नये, मागणाऱ्यास स्वतःजवळ कमी असतानाही द्यावे; या तीन गोष्टींना जीवनात स्थान देणारा श्रेष्ठजनांजवळ जातो ।",
  "225": "जो ज्ञानी अहिंसक वृत्तीचा आहे, सदैव शरीर-संयमित आहे, तो पतन-रहित स्थानी जातो, जेथे गेल्यावर पश्चात्ताप होत नाही ॥",
  "226": "जे सदैव जागृत असतात, अहोरात्र सन्मार्ग शिकत असतात, निर्वाणाचा संकल्प करतात, त्यांच्यातील दुर्विचार निघून जातात ।",
  "227": "हे अतुल! हे फार जुने आहे, हे असे आधुनिक नाही; गप्प राहणाऱ्याची निंदा होते, खूप बोलणाऱ्याची निंदा होते, कमी बोलणाऱ्याची निंदा होते; निंदा न होणारा लोकात कोणीही नाही ॥",
  "228": "असा मानव आता नाही, भविष्यातही नाही, दुसरीकडेही नाही, ज्याची केवळ निंदा होते वा केवळ प्रशंसा होते ।",
  "229": "ज्ञानी लोक सुजाणता त्यांची प्रशंसा रोज रोज करतात, जे छिद्रदोषरहित वृत्तीचे, सुज्ञ, प्रज्ञावान, शीलवान असतात ॥",
  "230": "जम्बोनदाच्या मोहरेसारख्या मानवाची निंदा करण्यायोग्य कोण आहे? श्रेष्ठजन व ब्रह्मा त्यांची प्रशंसा करतात ।",
  "231": "शरीर क्रोधापासून रक्षावे, शरीर संयमित ठेवावे; शारीरिक दुराचार सोडून शरीराने सदाचारी राहावे ॥",
  "232": "वाणीस क्रोधापासून रक्षावे, वाणी संयमित ठेवावी; वाणीचे दुराचार सोडून वाणीने सदाचारी राहावे ।",
  "233": "मनास क्रोधापासून रक्षावे, मन संयमित ठेवावे; मनाचे दुराचार सोडून मनाने सदाचारी राहावे ॥",
  "234": "शरीराने, वाणीने तसेच मनाने संयमित असणारे सुज्ञ, तेच खरोखर सुसंयमित असतात ।",
  "chap18": "मलवग्गो",
  "235": "आता तू पिवळ्या (पिकल्या) पानासारखा आहेस, जवळ यमदूत उभे आहेत; तू मृत्यूद्वारी उभा आहेस आणि तुझ्याजवळ प्रवासासाठी शिदोरीही नाही ॥",
  "236": "म्हणून तू स्वतःच स्वतःचा दीपक हो, त्वरित प्रयत्न करून ज्ञानी हो; म्हणजे मलरहित व दोषरहित होऊन तू दिव्य आर्य-भूमी प्राप्त करशील ।",
  "237": "आता तुझे आयुष्य अंतापर्यंत आणले आहे, तू यमाजवळ गेलेला आहेस; मध्ये कोठेही निवारा नाही आणि तुझ्याजवळ शिदोरीही नाही ॥",
  "238": "म्हणून तू स्वतःच स्वतःचा दीपक हो, त्वरित प्रयत्न करून ज्ञानी हो; म्हणजे मलरहित व दोषरहित होऊन तू पुन्हा जन्म-मृत्यू प्राप्त करणार नाहीस ।",
  "239": "प्रज्ञावान क्रमाने क्षणोक्षणी थोडा-थोडा स्वतःचा मळ दूर करतो, जसे सोनार चांदीचा मळ दूर करतो ॥",
  "240": "जसा लोखंडावर मळ (गंज) चढतो आणि तेथेच लोखंडाला खातो, तसे सदाचाराची मर्यादा उल्लंघनारे स्वकर्मानेच दुर्गतीला जातात ।",
  "241": "पठण नसणे हा मंत्रांचा मळ, अकार्यशीलता घराचा मळ, आळस वर्णाचा मळ आणि निष्काळजीपणा राखणदाराचा मळ असतो ॥",
  "242": "दुराचार हा स्त्रीचा मळ, कंजूषपणा दात्याचा मळ, दुष्कृत्य हे सदवर्तनाचा मळ आहे; या लोकात व दुसऱ्या लोकातही ।",
  "243": "या सर्व मळांहून अधिक मळ म्हणजे अविद्या हा मोठा मळ; सुजनांनो, या मळाला दूर करून निर्मळ व्हा ॥",
  "244": "बळकावण्यात शूर, निर्लज्ज कावळ्याप्रमाणे, उच्छृंखल, दुस्साहसी व कलुषित जीवन जगणे सोपे आहे ।",
  "245": "दुराचारास लज्जित, नित्य पावित्र्याचा ध्यास असणारे, शुद्धतेत निसंकोच व विस्तृत जीवन जगणे कठीण आहे ॥",
  "246": "जो या जगात प्राण्यांना मारतो, खोटे वचन बोलतो, जे दिलेले नाही ते घेतो, परस्त्रीकडे जातो ।",
  "247": "जो नशा-दारू पितो, असा मानव याच लोकात स्वतःचा पाया खणण्यात प्रवृत्त असतो ॥",
  "248": "म्हणून हे मानवा! दुराचार व असंयम जाणून घे; तुझे लोभ आणि दुराचार तुला कायमचे दुक्खात लोटू नयेत ।",
  "249": "लोक श्रद्धेनुसार व प्रसन्नतेनुसार दान देतात; जे इतर जनांच्या खान-पानात उत्साहहीन असतात, ते दिवसा किंवा रात्री एकाग्रचित्त होत नाहीत ॥",
  "250": "जे या ईर्ष्या भावनेचे संपूर्णपणे मुळासकट उच्चाटन करतात, ते दिवसा किंवा रात्री कधीही एकाग्रचित्त होतात ।",
  "251": "आसक्तीसारखी आग नाही, द्वेषासारखा ग्रह नाही, अज्ञानासारखे जाळे नाही, तृष्णेसारखा प्रवाह नाही ॥",
  "252": "इतरांचे दोष पाहणे सहज, स्वतःचे मात्र कठीण; दुसऱ्यांच्या दोषांना मानव भुशासारखे उडवतो, स्वतःचे दोष असे झाकतो जसे ठग स्वतःचा पराजय ।",
  "253": "जो दुसऱ्याचे दोष पाहणारा व कायम तक्रार करणारा असतो, त्याचे दुर्विचार वाढतात; त्याच्या दुर्विचारांचा क्षय होत नाही ॥",
  "254": "आकाशात डाग नाही, बुद्ध मार्गाबाहेर श्रमण नाही; सामान्यजन प्रपंचात मग्न असतात, तथागत प्रपंचहीन आहेत ।",
  "255": "आकाशात चिन्ह नाही, बुद्ध मार्गाबाहेर श्रमण नाही; संस्कार शाश्वत नाहीत, बुद्धांमध्ये संस्कारांचे औत्सुक्य नाही ॥",
  "chap19": "धम्मट्ठवग्गो",
  "256": "तो न्यायी होत नाही ज्याच्याकडून अर्थाची मनमानी होते; ज्ञानी मानव अर्थ-अनर्थ दोघांची निश्चिती करतो ।",
  "257": "जो मनमानी न करता, पक्षपात न करता न्यायाचे मार्गदर्शन करतो व सदाचाराचे रक्षण करतो, त्यालाच प्रज्ञावान व न्यायी म्हटले जाते ॥",
  "258": "जो खूप बोलतो तो ज्ञानी असत नाही; क्षमाशील, अवैरी आणि निर्भय असा मानव ज्ञानी म्हटला जातो ।",
  "259": "जोवर मानव फक्त खूप बोलतो तोवर तो धम्मधर होत नाही; जो थोडे ऐकून त्यानुसार शरीराने आचरण करतो आणि जो आचरणात बेपर्वा नसतो, तोच धम्मधर असतो ॥",
  "260": "डोक्यावरील केस पांढरे झाल्याने कोणी थोर होत नाही; फक्त त्याचे वय परिपक्व होते, तो व्यर्थच म्हातारा म्हणविला जातो ।",
  "261": "ज्यात सत्य, अहिंसा, संयम व धीर असतो, तो निर्मळ व बुद्धिमान मानव थोर म्हणविला जातो ॥",
  "262": "केवळ बोलणे चांगले असण्याने किंवा कमळासारखा वर्ण लाभल्याने ईर्ष्यावान, मत्सरी व शठ मानव साधू होत नाही ।",
  "263": "जो या ईर्ष्या-मत्सर भावनेचे मुळासकट उच्चाटन करतो, तो दोषहीन व प्रज्ञावान मानव साधू म्हणविला जातो ॥",
  "264": "व्रतस्थ नसलेला व अयोग्य बोलणारा मुंडण केल्याने श्रमण होत नाही; इच्छा-लोभाने भारलेला श्रमण कसा होईल? ।",
  "265": "जो लहान-मोठ्या सर्व दुष्कर्मांचे निवारण करतो, तो दुष्कर्म निवारण्याने श्रमण म्हणविला जातो ॥",
  "266": "तो केवळ भिक्षा मागतो म्हणून भिक्खू होत नाही; जोपर्यंत तो त्याज्य गुणांचा अंगीकार करतो तो भिक्खू होत नाही ।",
  "267": "जो पाप-पुण्याच्या सीमेपार आहे, ब्रह्मचारी आहे आणि जो विचारपूर्वक आचरण करतो, तो भिक्खू म्हणविला जातो ॥",
  "268": "फक्त मौन पालनाने मूर्ख व अज्ञानी मानव मुनी होत नाही; जो तराजू धारण केल्याप्रमाणे उत्तमाचे ग्रहण करतो, तोच ज्ञानी ।",
  "269": "मनन करून जो दुष्कृत्याचा त्याग करतो तो मुनी; दोन्ही लोकांमद्दल मनन करून जो आचरतो त्याला मुनी म्हटले जाते ॥",
  "270": "प्राण्यांना मारतो तो सज्जन होत नाही; जो सर्व प्राण्यांशी अहिंसेने वागतो त्याला सज्जन म्हटले जाते ।",
  "271": "शीलवान होऊन, व्रतस्थ होऊन, खूप सदुपदेश ऐकून किंवा एकाग्रचित्त होऊन, एकान्त राहून ॥",
  "272": "संसारत्यागाचे सुख, जे असामान्य जणच अनुभवतात, ते मी अनुभवले आहे असे समजून, हे भिक्खू! चित्त-मल-क्षय होईतो विश्वस्त होऊ नका ।",
  "chap20": "मग्गवग्गो",
  "273": "मार्गांत अष्टांग मार्ग श्रेष्ठ, सत्यात चार आर्यसत्ये, सिद्धांतात निर्वाण श्रेष्ठ आणि मानवांत बुद्ध श्रेष्ठ ॥",
  "274": "विशुद्धीच्या दर्शनाचा हा एकच मार्ग आहे, दुसरा नाही; तुम्ही याच मार्गावर चला, हा मार्गच भुलभुलैयाला भुलवितो ।",
  "275": "या मार्गानेच तुम्ही दुक्खाचा अंत करू शकाल; हा मार्ग मी स्वतः वेदनेचे कारण समजून सांगितला आहे ॥",
  "276": "तुम्हालाच प्रयत्न करायचा आहे, तथागत केवळ मार्गदर्शक आहेत; या मार्गाक्रमणाने एकाग्र होऊन तुम्ही भुलैयाच्या बंधनातून मुक्त व्हाल ।",
  "277": "सर्व संस्कार अनित्य आहेत, हे जेव्हा प्रज्ञेने पाहतो तेव्हा दुक्खाची अवहेलना होते; हाच विशुद्धीचा मार्ग आहे ॥",
  "278": "सर्व संस्कार दुक्खद आहेत, हे जेव्हा प्रज्ञेने पाहतो तेव्हा दुक्खाची अवहेलना होते; हाच विशुद्धीचा मार्ग आहे ।",
  "279": "सर्व स्वभाव अनित्य आहेत, हे जेव्हा प्रज्ञेने पाहतो तेव्हा दुक्खाची अवहेलना होते; हाच विशुद्धीचा मार्ग आहे ॥",
  "280": "उठण्याच्या वेळीही जो उठत नाही, तरुण व बलवान असूनही आळसावलेला असतो, सुसंकल्प आळसाने दवडतो, अशा आळशी मानवाला प्रज्ञामार्ग प्राप्त होत नाही ।",
  "281": "जो वाणीचे रक्षण करतो, मन संयमित ठेवतो आणि शरीराने अयोग्य कृत्य करीत नाही; या तिन्हींना कर्ममार्गावर शुद्ध ठेवणारा श्रेष्ठजनांनी सांगितलेला मार्ग प्राप्त करतो ॥",
  "282": "अभ्यासाने प्रज्ञा उत्पन्न होते, अनभ्यासाने प्रज्ञेची हानी होते; उत्पत्ती व विनाश या दोन्हींची जाणीव ठेवून स्वतःला प्रज्ञेत स्थापित केल्याने प्रज्ञेची वृद्धी होते ।",
  "283": "तृष्णेचे जंगल तोडा, वृक्ष तोडू नका; जंगलाने भीती उत्पन्न होते; हे भिक्खूंनो, झुडपे तोडून तृष्णाहीन व्हा ॥",
  "284": "जोवर पुरुषाची स्त्रीबद्दलची तृष्णा अणुमात्रही उरलेली असते, तोवर तो मनाने बद्ध असतो, जसे दूध पिणारे वासरू मातेशी ।",
  "285": "शरद ऋतूत कमळ तोडावे तसा स्वतःचा स्नेह तोडावा आणि बुद्धाने उपदेशिलेला निर्वाणाचा मार्ग जोडावा ॥",
  "286": "इथे वर्षा ऋतूत, इथे हेमंतात वा ग्रीष्मात वास्तव्य करीन, असा अजाण मानव विचार करतो; तो मोहाचे विघ्न जाणत नाही ।",
  "287": "पुत्र व पशु यांच्या लोभात आसक्त मानवाला नदीच्या पुराप्रमाणे मृत्यू घेऊन जातो ॥",
  "288": "जेव्हा मृत्यू तुम्हास पकडतो, तेव्हा ना पुत्र, ना पिता, ना बंधू, ना नातेवाईक तुमचे रक्षण करू शकतात ।",
  "289": "या सत्याचा प्रभाव जाणून शीलवान व ज्ञानी मानवांनी निर्वाणाकडे जाणारा मार्ग त्वरित शोधावा ॥",
  "chap21": "पकिण्णकवग्गो",
  "290": "मर्यादित सुखाच्या त्यागाने जर विपुल सुखप्राप्ती दिसत असेल, तर विद्वान मानवाने मर्यादित सुख त्यागून विपुल सुखाकडे पहावे ।",
  "291": "दुसऱ्याला दुक्ख देऊन जो स्वतःचे सुख इच्छितो, शत्रुत्वाच्या संपर्कातील अशा मानवाची शत्रूपासून मुक्ती होत नाही ॥",
  "292": "जे कर्तव्य आहे त्याचा अव्हेर करून जे अकर्तव्य आहे ते जो करतो, त्या अहंकारी व प्रमादी मानवाचे चित्तविकार वाढतात ।",
  "293": "ज्यांची शारीरिक-जागरूकता सदैव तत्पर असते, जे अकृत्य करीत नाहीत आणि सत्कृत्य सातत्याने करतात, त्या कार्यमग्न मानवाचे चित्तविकार विनाशाकडे जातात ॥",
  "294": "तृष्णा व अहंकार यांचा त्याग करून, चुकीच्या दृष्टींचा वध करून, राज्याचा संहार करून ब्राह्मण सुजन दुक्खविहीन होतो ।",
  "295": "तृष्णा व अहंकार यांचा त्याग करून, चुकीच्या दृष्टींचा वध करून, पाच आवरणे नष्ट करून ब्राह्मण सुजन दुक्खविहीन होतो ॥",
  "296": "गौतम-शिष्यांची तीक्ष्ण बुद्धी सदैव जागृत असते, ज्यांची स्मृती रात्रंदिवस नित्य बुद्धांकडे असते ।",
  "297": "गौतम-शिष्यांची तीक्ष्ण बुद्धी सदैव जागृत असते, ज्यांची स्मृती रात्रंदिवस नित्य धम्माकडे असते ॥",
  "298": "गौतम-शिष्यांची तीक्ष्ण बुद्धी सदैव जागृत असते, ज्यांची स्मृती रात्रंदिवस नित्य संघाकडे असते ।",
  "299": "गौतम-शिष्यांची तीक्ष्ण बुद्धी सदैव जागृत असते, ज्यांची स्मृती रात्रंदिवस नित्य शरीराच्या भानाकडे असते ॥",
  "300": "गौतम-शिष्यांची तीक्ष्ण बुद्धी सदैव जागृत असते, जे रात्रंदिवस नित्य मनःपूर्वक अहिंसेत मग्न असतात ।",
  "301": "(त्या) गौतम-शिष्यांची तीक्ष्ण बुद्धी सदैव जागृत असते, जे रात्रंदिवस नित्य मनोभावनेत (मनाच्या सद्भावनेत) मग्न असतात ॥",
  "302": "प्रवज्जित असणे दुष्कर, भोगात राहणे दुष्कर, गृहस्थाचे घरी राहणे दुक्खकर, असमान लोकांत राहणे दुक्खकर आणि भवचक्रात पडणे दुक्खकर; म्हणून भवचक्रात व दुक्खात पडू नये ॥",
  "303": "जो श्रद्धा व शीलाने संपन्न असतो, यश व संपत्तीचे समर्पण करतो, तो ज्या ज्या स्थानी जातो तेथे तेथे पुजला जातो ।",
  "304": "सत्पुरुष बर्फाच्छादित पर्वतासारखे लांबूनही प्रकाशित दिसतात; असत्पुरुष रात्री अंधारात फेकलेल्या बाणासारखे अदृश्य राहतात ॥",
  "305": "एक आसनी, एक शय्येवर राहणारा, न थकता एकटा राहणारा आणि स्वतःचे एकट्याने संयमन करणारा वनात रममाण असतो ।",
  "chap22": "निरयवग्गो",
  "306": "असत्य बोलणारे नरकात जातात, आणि दुष्कृत्य करूनही 'मी केले नाही' असे सांगणारे सुद्धा; मृत्यूनंतर दोघेही परलोकात सारखेच शिक्षा भोगतात ॥",
  "307": "काषाय वस्त्र परिधान करणारे अनेक लोक दुर्गुणी व असंयमी असतात; ते त्यांच्या दुष्कृत्यांमुळे नरकात उत्पन्न होतात ।",
  "308": "शीलभ्रष्ट व असंयमी होऊन जनतेचे अन्न खाण्यापेक्षा, अग्निज्वाळांसारखा तप्त लोखंडाचा गोळा खाणे अधिक चांगले ॥",
  "309": "परस्त्रीच्या संगतीत राहणाऱ्या पुरुषाच्या चार गती होतात: अपुण्य लाभ, शांत झोप न येणे, तिसरी निंदा आणि चौथी नरकवास ।",
  "310": "अपुण्य लाभ आणि दुर्गती होते; भयग्रस्ताची भयभीता स्त्रीशी अल्पकाळ रतिक्रीडा होते आणि राजाकडून कठोर सजा मिळते; म्हणून माणसाने परस्त्री भोग करू नये ॥",
  "311": "गवताची पाती नीट न धरल्यास ती हाताला जखमी करतात; तसेच श्रमण्य धर्माचे नीट पालन न केल्यास ते मानवाला नरकात ढकलते ।",
  "312": "शिथिलपणे केलेले कोणतेही कार्य, मलिनपणे केलेले व्रत आणि साशंक ब्रह्मचर्य यांचे फळ मोठे नसते ॥",
  "313": "जे करायचे असेल ते दृढ पराक्रमाने करावे; शिथिलतेने प्रव्रज्या पाळणारा उलट अधिक रज (मळ) उडवितो ।",
  "314": "दुष्कृत्य न करणे चांगले कारण दुष्कृत्याने पश्चात्ताप होतो; सत्कृत्य करणे चांगले कारण ते केल्याने पश्चात्ताप होत नाही ॥",
  "315": "जसे नगर आतून-बाहेरून संरक्षित असते, तसे स्वतःला सुरक्षित ठेवावे; एक क्षणही वाया जाऊ देऊ नये, कारण क्षण गमावल्यास नरकात पडावे लागते ।",
  "316": "लाज वाटू नये तेथे ज्यांना लाज वाटते, पण लाजिरवाण्या कामात लाज वाटत नाही, अशी खोटी समजूत बाळगणारे लोक दुर्गतीला जातात ॥",
  "317": "भीती वाटू नये तिथे जे भितात, पण भीती वाटावी तिथे भीत नाहीत, अशी खोटी समजूत बाळगणारे लोक दुर्गतीला जातात ।",
  "318": "अवर्ज्य ते वर्ज्य मानतात आणि वर्ज्य ते अवर्ज्य मानतात, अशी मिथ्या दृष्टी बाळगणारे लोक दुर्गतीला जातात ॥",
  "319": "वर्ज्य ते वर्ज्य आणि अवर्ज्य ते अवर्ज्य मानणारे, अशी सम्यक दृष्टी बाळगणारे लोक सुगती प्राप्त करतात ।",
  "chap23": "नागवग्गो",
  "320": "युद्धात जसा हत्ती धनुष्यातून सुटलेल्या बाणांना सहन करतो, तसे मी अपशब्द सहन करीन; कारण जगात खूप दुर्जन आहेत ॥",
  "321": "संयमित प्राण्यासच सभेत नेतात, संयमित हत्तीवरच राजा स्वार होतो; जो अपशब्द सहन करतो तो संयमित मानव श्रेष्ठ आहे ।",
  "322": "संयमित खेचर, जातिवंत सिंधी घोडा आणि महानाग हत्ती श्रेष्ठ आहेत; परंतु त्याहूनही स्वतःला संयमित करणारा मानव अधिक श्रेष्ठ आहे ॥",
  "323": "या वाहनांनी (घोडा, हत्ती) त्या अगम्य प्रदेशात (निर्वाण) जाता येत नाही, जेथे स्व-संयमित मानव आपल्या संयमामुळे सहज जातो ।",
  "324": "धनपालक नावाचा हत्ती अंकुश मानत नाही, तो रोखण्यास कठीण असतो; बंधनात असताना तो काहीही न खाता आपल्या हत्ती-वनाची आठवण काढत राहतो ॥",
  "325": "माणूस जेव्हा आळशी, खादाड आणि लोळत झोपणारा होतो, तेव्हा चारा खाऊन माजलेल्या डुकराप्रमाणे तो पुन्हा-पुन्हा गर्भात पडतो (जन्म घेतो) ।",
  "326": "यापूर्वी हे चित्त स्वतःच्या इच्छेनुसार, सुख वाटेल तिथे विहरले; आजपासून मी या चित्ताला निग्रहाने आवरून धरीन, जसा अंकुशधारी हत्तीला आवरतो ॥",
  "327": "अप्रमादात रममाण होऊन आपल्या चित्ताचे रक्षण करावे; चिखलात रुतलेल्या हत्तीने स्वतःला बाहेर काढावे, तसे स्वतःला कठीण मार्गातून वर न्यावे ।",
  "328": "जर दक्ष, बुद्धिमान आणि सदाचारी मित्र लाभला, तर सर्व विघ्नांवर मात करून प्रसन्न चित्ताने त्याच्यासोबत राहावे ॥",
  "329": "जर दक्ष आणि बुद्धिमान मित्र लाभला नाही, तर पराजित राष्ट्र सोडून एकटा अरण्यात राहणाऱ्या 'मातंग' राजा हत्तीप्रमाणे एकटे राहावे ।",
  "330": "अज्ञानी मानवाची मैत्री करण्यापेक्षा एकटे राहणे चांगले; दुष्कृत्य न करता, मातंग हत्तीप्रमाणे अनासक्त होऊन एकटे विहरावे ॥",
  "331": "गरज असताना मित्र सुखावह असतो, कोणत्याही कारणाने लाभलेली संतुष्टी सुखावह असते; मृत्यूप्रसंगी सत्कृत्य सुखावह असते, पण सर्व दुक्खाचा नाश होणे हे सर्वाधिक सुखावह आहे ।",
  "332": "जगात माता-पित्याची सेवा सुखावह आहे, श्रमणत्व सुखावह आहे आणि श्रेष्ठ जीवन जगणे सुखावह आहे ॥",
  "333": "वृद्धत्वापर्यंत शील पाळणे सुखावह आहे, दृढ श्रद्धा सुखावह आहे, प्रज्ञाप्राप्ती सुखावह आहे आणि दुष्कृत्य न करणे हे सर्वात सुखावह आहे ।",
  "chap24": "तण्हावग्गो",
  "334": "प्रमादी माणसाची तृष्णा वेलीसारखी वाढते; वनात फळाच्या इच्छेने उड्या मारणाऱ्या वानराप्रमाणे तो एका जन्मातून दुसऱ्या जन्मात उड्या मारतो ॥",
  "335": "ही विषारी तृष्णा ज्याला जिंकते, त्याचे दुःख पावसाळ्यात वाढणाऱ्या 'बीरण' गवताप्रमाणे वाढत जाते ।",
  "336": "जो या दुर्लाघ्य तृष्णेला जिंकतो, त्याचे शोक गळून पडतात, जसे कमळाच्या पानावरून पाण्याचे थेंब ॥",
  "337": "तुमचे मंगल असो! तृष्णेचे मूळ खणून काढा; 'खस' मुळासाठी जसे बीरण गवत खणतात, तसे करा म्हणजे मार (भुलैया) पुन्हा पुन्हा हानी करणार नाही ।",
  "338": "मुळे शाबूत असल्यास तोडलेला वृक्षही पुन्हा उगवतो; तसेच तृष्णेची वृत्ती मुळासकट नष्ट केली नाही, तर दुःख पुन्हा पुन्हा उत्पन्न होते ॥",
  "339": "ज्याचे छत्तीस स्रोत मनाला प्रिय वाटणाऱ्या विषयांकडे धावतात, त्या भ्रष्ट दृष्टीच्या मानवाचे संकल्प आसक्तीवर आधारित असतात ।",
  "340": "तृष्णेचे सर्व स्रोत वाहत राहतात आणि तृष्णारूपी वेल अंकुरित होत राहते; ती वेल उगवताना दिसताच प्रज्ञेने तिची मुळे कापावीत ॥",
  "341": "प्राण्यांना स्नेहरूपी नद्या प्रसन्न वाटतात; सुखाच्या शोधात ते विषयांकडे धावतात आणि जन्म-मृत्यूच्या चक्रात गुंततात ।",
  "342": "तृष्णेने घेरलेले लोक जाळ्यात अडकलेल्या सशासारखे धावत राहतात; आसक्तीने बांधलेले मानव दीर्घकाळ दुःखाकडेच येतात ॥",
  "343": "तृष्णेने घेरलेले लोक अडकलेल्या सशासारखे तडफडतात; म्हणून वैराग्याची इच्छा असलेल्या भिक्खूने तृष्णेचा त्याग करावा ।",
  "344": "जो संसारातून मुक्त होऊन वनाकडे जातो पण पुन्हा संसाराकडे धावतो, तो मुक्त होऊनही पुन्हा बंधनाकडे धावणारा मूर्ख होय ॥",
  "345": "लोखंडाच्या वा लाकडाच्या बेड्यांना ज्ञानी लोक दृढ बंधन मानत नाहीत; सोने-नाणे, पुत्र आणि पत्नी यांमधील आसक्ती हेच खरे दृढ बंधन होय ।",
  "346": "या सुटण्यास कठीण बंधनांना ज्ञानी लोक शिथिल मानून तोडून टाकतात; ते कामसुख त्यागून अनपेक्षितपणे प्रव्रजित होतात ॥",
  "347": "आसक्तीत रमणारे लोक प्रवाहाबरोबर वाहून जातात, जसा कोळी स्वतःच्या जाळ्यात अडकतो; ज्ञानी लोक ही बंधने तोडून सर्व दुःखाचा त्याग करतात ।",
  "348": "भूतकाळ, भविष्यकाळ आणि वर्तमानकाळातील आसक्ती सोडून भवसागराच्या पलीकडे जा; मनाला सर्व बाजूंनी मुक्त करणारे पुन्हा जन्म-मृत्यूच्या फेऱ्यात येत नाहीत ॥",
  "349": "कुतर्कात पडलेल्या आणि तीव्र आसक्ती असलेल्या जीवांची तृष्णा वाढत जाते; ते वास्तवात आपली बंधने अधिक घट्ट करतात ।",
  "350": "जे विचारांना शांत करण्यात मग्न आहेत आणि सदैव जागरूक राहून अशुभाचे चिंतन करतात, ते तृष्णा नष्ट करून मार-बंधन छेदून जातात ॥",
  "351": "जो ध्येयाप्रत पोहोचला आहे, जो निर्भय, तृष्णाहीन आणि निष्पाप आहे, ज्याने अज्ञानाचे काटे उखडून टाकले आहेत, हा त्याचा अंतिम जन्म होय ।",
  "352": "जो तृष्णाहीन, अपरिग्रही आणि शब्दांचा क्रम व अर्थ जाणणारा पंडित आहे, तो महाप्रज्ञावान म्हणविला जातो; हे त्याचे अंतिम शरीर आहे ॥",
  "353": "मी सर्वविजयी, सर्वज्ञ आणि सर्व आसक्तींपासून मुक्त आहे; तृष्णेचा क्षय झाल्यामुळे मी पूर्णपणे मुक्त आहे, आता मी कोणाला गुरु मानू? ।",
  "354": "धम्मदान हे सर्व दानांमध्ये श्रेष्ठ आहे, धम्मरस सर्व रसांमध्ये श्रेष्ठ आहे; धम्मातील आनंद सर्व आनंदांत श्रेष्ठ आहे आणि तृष्णाक्षय सर्व दुःखांवर विजय मिळवतो ॥",
  "355": "भोग दुर्बुद्ध माणसाला नष्ट करतात; भोगाच्या तृष्णेमुळे असा माणूस इतरांप्रमाणे स्वतःचाच नाश करून घेतो ।",
  "356": "गवत हा शेताचा दोष आहे, आसक्ती हा या मनुष्यजातीचा दोष आहे; म्हणून अनासक्ताला दिलेल्या दानाचे फळ मोठे असते ॥",
  "357": "गवत हा शेताचा दोष आहे, द्वेष हा या लोकांचा दोष आहे; म्हणून द्वेषहीनास दिलेल्या दानाचे फळ मोठे असते ।",
  "358": "गवत हा शेताचा दोष आहे, मोह हा या लोकांचा दोष आहे; म्हणून निर्मोही व्यक्तीला दिलेल्या दानाचे फळ मोठे असते ॥",
  "359": "गवत हा शेताचा दोष आहे, इच्छा हा या लोकांचा दोष आहे; म्हणून निरीच्छ व्यक्तीला दिलेल्या दानाचे फळ मोठे असते ।",
  "chap25": "भिक्खुवग्गो",
  "360": "डोळ्यांवर संयम असणे चांगले, कानांवर संयम असणे चांगले; नाकावर संयम असणे चांगले आणि जिभेवर संयम असणे चांगले ॥",
  "361": "शरीराचा, वाचेचा आणि मनाचा संयम असणे चांगले; सर्वत्र संयमित असणारा भिक्खू सर्व दुःखांतून मुक्त होतो ।",
  "362": "ज्याचे हात, पाय आणि वाणी संयमित आहेत, जो स्वतःमध्ये रममाण असून एकटा मनन करतो आणि संतुष्ट राहतो, तोच खरा भिक्खू ॥",
  "363": "जो वाणीने संयमित आहे, विचारपूर्वक बोलतो, निरहंकारी आहे आणि धम्माचा अर्थ उलगडून सांगतो, त्याचे बोलणे मधुर असते ।",
  "364": "जो धम्मात विहरतो, धम्मात रममाण होतो, धम्माचे चिंतन आणि अनुसरण करतो, तो भिक्खू धम्मापासून कधीही ढळत नाही ॥",
  "365": "स्वतःला जे मिळाले आहे त्याची अवहेलना करू नये आणि इतरांच्या लाभाचा हेवा करू नये; हेवा करणारा भिक्खू कधीही एकाग्र होऊ शकत नाही ।",
  "366": "अल्प लाभ होऊनही जो भिक्खू त्याची अवहेलना करीत नाही, त्या शुद्ध जीवन जगणाऱ्या भिक्खूची देवही प्रशंसा करतात ॥",
  "367": "ज्याला 'मी' आणि 'माझे' याबद्दल कोणतीही आसक्ती नाही आणि जे नाही त्याबद्दल जो शोक करीत नाही, त्यालाच भिक्खू म्हणतात ।",
  "368": "मैत्रीभावाने राहणारा आणि बुद्ध-उपदेशाने प्रसन्न होणारा भिक्खू शांत अशा निर्वाण पदाला प्राप्त होतो ॥",
  "369": "भिक्खू! ही होडी (शरीर/चित्त) रिकामी कर; रिकामी होडी वेगाने धावेल. आसक्ती आणि द्वेष तोडून टाक म्हणजे तू निर्वाणाप्रत पोहोचशील ।",
  "370": "पाच बंधने तोडा, पाच सोडा आणि पाच गुणांचे संवर्धन करा; पाच आसक्तींना पार करणारा भिक्खू 'ओघतिण्ण' (प्रवाह पार केलेला) म्हणविला जातो ॥",
  "371": "भिक्खू! ध्यान कर, प्रमाद करू नकोस; तुझे चित्त कामगुणांत भरकटू देऊ नकोस. गाफील राहून तप्त लोहगोळा गिळू नकोस, जेणेकरून जळताना तुला 'हे दुःख आहे' म्हणून आक्रोश करावा लागू नये ।",
  "372": "प्रज्ञाहीनाला ध्यान लाभत नाही आणि ध्यान नसलेल्याला प्रज्ञा लाभत नाही; ज्याच्याकडे ध्यान व प्रज्ञा दोन्ही आहेत, तोच निर्वाणाजवळ आहे ॥",
  "373": "एकांतात राहणारा आणि शांत चित्त असलेला भिक्खू जेव्हा धम्माचा साक्षात्कार करतो, तेव्हा त्याला अलौकिक आनंद मिळतो ।",
  "374": "जेव्हा जेव्हा माणूस पंचस्कंधांच्या उत्पत्ती आणि विनाशाचे आकलन करतो, तेव्हा त्याला अमृताची प्राप्ती झाल्यासारखा परमानंद होतो ॥",
  "375": "प्रज्ञावान भिक्खूने सुरुवातीला इंद्रिय-संयम, संतुष्टी आणि भिक्खू नियमांचे (पातिमोक्ख) पालन केले पाहिजे ।",
  "376": "शुद्ध आचरण असलेल्या आणि क्रियाशील मित्राची संगत करावी; मैत्रीपूर्ण आणि सदाचारी राहावे, त्यातूनच आनंदित होऊन दुःखाचा अंत करावा ॥",
  "377": "जशी चमेलीची वेल कोमेजलेली फुले टाकून देते, तसे भिक्खूंनो, तुम्ही आसक्ती आणि द्वेष टाकून दिला पाहिजे ।",
  "378": "ज्याची काया, वाणी आणि चित्त शांत आहे, जो एकाग्र असून लौकिक आमिषांपासून दूर आहे, त्या भिक्खूला 'उपशांत' म्हणतात ॥",
  "379": "जो स्वतःच स्वतःला प्रेरित करतो आणि स्वतःचे परीक्षण करतो, तो आत्मसंयमी व स्मृतिवान भिक्खू सुखात राहतो ।",
  "380": "माणूस स्वतःच स्वतःचा स्वामी आणि स्वतःच स्वतःची गती आहे; म्हणून जसा व्यापारी उमद्या घोड्याला आवरतो, तसे स्वतःला संयमित ठेवा ॥",
  "381": "जो भिक्खू आनंदित चित्ताने बुद्धाच्या शिकवणीत प्रसन्न राहतो, तो सर्व संस्कारांचे शमन करून शांत अशा निर्वाण पदाला पोहोचतो ।",
  "382": "जो भिक्खू तरुणपणीच बुद्धाच्या शिकवणीत मग्न होतो, तो ढगमुक्त चंद्राप्रमाणे या जगाला प्रकाशित करतो ॥",
  "chap26": "ब्राह्मणवग्गो",
  "383": "हे ब्राह्मणा! पराक्रम गाजवून तृष्णेचा स्रोत तोडून टाक आणि कामना दूर कर; संस्कारांचा क्षय जाणून घेऊन अकृताचा (निर्वाणाचा) जाणकार हो ॥",
  "384": "जेव्हा ब्राह्मण शम आणि दमन या दोन गुणांत पारंगत होतो, तेव्हा त्या ज्ञानी व्यक्तीची सर्व बंधने नष्ट होतात ।",
  "385": "ज्याला अलीकडचा तीर (इंद्रिये) नाही की पलीकडचा तीर (विषय) नाही, जो निर्भय आणि बंधमुक्त आहे, त्यालाच मी ब्राह्मण म्हणतो ॥",
  "386": "जो ध्यानमग्न, निर्मळ, कर्तव्यदक्ष आणि आसक्तीहीन आहे, ज्याने परम अर्थ प्राप्त केला आहे, त्यालाच मी ब्राह्मण म्हणतो ।",
  "387": "दिवसा सूर्य तळपतो, रात्री चंद्र प्रकाशतो, शस्त्रांसह क्षत्रिय तळपतो, ध्यानमग्न ब्राह्मण तळपतो; परंतु बुद्ध आपल्या तेजाने दिवस-रात्र प्रकाशत असतात ॥",
  "388": "ज्याचे पाप वाहून गेले आहे तो ब्राह्मण, ज्याचे आचरण सम्यक आहे तो श्रमण आणि ज्याने स्वतःचे मळ दूर केले आहेत तो प्रव्रजित म्हणविला जातो ।",
  "389": "ब्राह्मणावर प्रहार करू नये आणि ब्राह्मणानेही क्रोध करू नये; ब्राह्मणाला मारणाऱ्याचा धिक्कार असो, पण जो क्रोधाला वाट करून देतो त्याचा अधिक धिक्कार असो ॥",
  "390": "मनाला प्रिय असलेल्या विषयांपासून रोखणे हे ब्राह्मणासाठी श्रेष्ठ आहे; जसे जसे मन हिंसेपासून निवृत्त होते, तसे तसे दुःख शांत होते ।",
  "391": "ज्याने काया, वाणी आणि मनाने कोणतेही दुष्कृत्य केलेले नाही, जो या तिन्ही ठिकाणी संयमित आहे, त्यालाच मी ब्राह्मण म्हणतो ॥",
  "392": "सम्यक संबुद्धाने उपदेशिलेला धम्म ज्याच्याकडून शिकायला मिळतो, त्याला तसाच आदरपूर्वक नमस्कार करावा जसा ब्राह्मण अग्नीला करतो ।",
  "393": "ना जटेने, ना गोत्राने, ना जन्माने कोणी ब्राह्मण होतो; ज्याच्यात सत्य आणि धम्म आहे तोच खरोखर शुद्ध आणि ब्राह्मण होय ॥",
  "394": "हे दुर्बुद्ध मानवा! या जटा आणि हे मृगाजिन कशासाठी? तुझे अंतःकरण विकारांनी भरलेले आहे आणि तू केवळ बाहेरून स्वतःला घासून पुसून स्वच्छ करतो आहेस ।",
  "395": "जो चिंध्या परिधान करतो, जो कृश आहे, ज्याच्या धमन्या दिसत आहेत आणि जो वनात एकटा ध्यानस्थ असतो, त्यालाच मी ब्राह्मण म्हणतो ॥",
  "396": "केवळ ब्राह्मण मातेपोटी जन्म घेतला म्हणून मी त्याला ब्राह्मण म्हणत नाही; जर तो आसक्त असेल तर तो केवळ 'भो-वादी' (सन्माननीय म्हणवून घेणारा) आहे. जो अपरिग्रही आणि अनासक्त आहे, त्यालाच मी ब्राह्मण म्हणतो ।",
  "397": "सर्व बंधने तोडून जो निर्भय झाला आहे, ज्याने सर्व पाश तोडले आहेत, त्यालाच मी ब्राह्मण म्हणतो ॥",
  "398": "ज्याने रागाची नाडी, द्वेषाचा पट्टा आणि मोहाची साखळी तोडली आहे, जो अज्ञानरूपी जुगार झिडकारून बुद्ध झाला आहे, त्यालाच मी ब्राह्मण म्हणतो ।",
  "399": "जो शिव्या, प्रहार आणि बंधने अपराधाशिवाय सहन करतो, क्षमा हेच ज्याचे प्रबळ सैन्य आहे, त्यालाच मी ब्राह्मण म्हणतो ॥",
  "400": "जो अक्रोधी, व्रतस्थ, शीलवान, तृष्णाहीन आणि संयमित आहे, ज्याचा हा अंतिम जन्म आहे, त्यालाच मी ब्राह्मण म्हणतो ।",
  "401": "कमळाच्या पानावर जलबिंदू वा सुईच्या टोकावर मोहरी जशी टिकत नाही, तसा जो कामनांना चिकटून राहत नाही, त्याला मी ब्राह्मण म्हणतो ॥",
  "402": "जो आपल्या दुक्खाचा क्षय इथेच स्पष्टपणे जाणतो, जो भारमुक्त आणि सर्व बंधनांतून मुक्त आहे, त्याला मी ब्राह्मण म्हणतो ।",
  "403": "जो गंभीर प्रज्ञेचा, सुजाण, मार्ग आणि अमार्गाचा जाणकार आहे, ज्याला परम अर्थ प्राप्त झाला आहे, त्याला मी ब्राह्मण म्हणतो ॥",
  "404": "जो गृहस्थ आणि गृहहीन या दोघांपासूनही अलिप्त आहे, जो घरादारापासून दूर आणि निरीच्छ आहे, त्याला मी ब्राह्मण म्हणतो ।",
  "405": "जो स्थावर आणि जंगम प्राण्यांना दंड देण्यापासून अलिप्त असतो, जो ना कोणाला मारतो ना कोणाचा घात करतो, त्याला मी ब्राह्मण म्हणतो ॥",
  "406": "विरोधकांमध्ये जो अविरोधी, दंडधाऱ्यांमध्ये जो शांत आणि परिग्रही लोकांत जो अपरिग्रही आहे, त्याला मी ब्राह्मण म्हणतो ।",
  "407": "ज्याच्या चित्तातून मोह, द्वेष, मान, अहंकार आणि मत्सर तसे गळून पडले आहेत जशी सुईच्या टोकावरून मोहरी गळून पडते, त्याला मी ब्राह्मण म्हणतो ॥",
  "408": "जो अप्रिय न बोलता सदैव सत्य वचन बोलतो, ज्याच्या बोलण्याने कोणीही क्रोधित होत नाही, त्याला मी ब्राह्मण म्हणतो ।",
  "409": "लांब वा आखूड, लहान वा मोठी, चांगली वा वाईटजी वस्तू दिलेली नाही ती जो स्वतःहून घेत नाही (चोरी करीत नाही), त्याला मी ब्राह्मण म्हणतो ॥",
  "410": "ज्याला या लोकात वा परलोकात कोणतीही आशा उरलेली नाही, जो पूर्णपणे निरीच्छ आणि बंधमुक्त आहे, त्याला मी ब्राह्मण म्हणतो ।",
  "411": "ज्याच्या मनात संशयाला कोणतेही स्थान उरलेले नाही, ज्याला अगाध अमृताची (निर्वाणाची) प्राप्ती झाली आहे, त्याला मी ब्राह्मण म्हणतो ॥",
  "412": "ज्याने पुण्य आणि पाप या दोन्ही आसक्ती ओलांडल्या आहेत, जो शुद्ध आणि शोकरहित आहे, त्याला मी ब्राह्मण म्हणतो ।",
  "413": "जो चंद्रासारखा निर्मळ, शुद्ध, सुस्पष्ट आणि स्वच्छ मनाचा आहे, ज्याचा भव-राग (अस्तित्वाची ओढ) क्षीण झाला आहे, त्याला मी ब्राह्मण म्हणतो ॥",
  "414": "ज्याने हा धोकादायक आणि दुर्गम संसार-मोह ओलांडला आहे, जो ध्यानात उत्तीर्ण, तृष्णेच्या पार गेलेला आणि निःसंशयी आहे, ज्याच्या निवृत्तीला कोणतेही कारण उरले नाही, त्याला मी ब्राह्मण म्हणतो ।",
  "415": "जो वासनांचा नाश करून बेघर होऊन प्रव्रजित झाला आहे, ज्याचा वासना-भाव पूर्णतः क्षीण झाला आहे, त्याला मी ब्राह्मण म्हणतो ॥",
  "416": "जो तृष्णेचा पूर्ण निःपात करून बेघर होऊन प्रव्रजित झाला आहे, ज्याचा तृष्णा-भाव पूर्णतः क्षीण झाला आहे, त्याला मी ब्राह्मण म्हणतो ।",
  "417": "ज्याने मानवी संबंध तोडले आहेत आणि जो दिव्य संबंधांच्याही पलीकडे गेला आहे, जो सर्व प्रकारच्या योगांपासून (बंधनांपासून) विलग आहे, त्याला मी ब्राह्मण म्हणतो ॥",
  "418": "जो प्रीती आणि अप्रीती सोडून शांत-भाव प्राप्त झालेला व क्लेशहीन आहे, ज्या वीराने सर्व प्रपंचावर विजय मिळवला आहे, त्याला मी ब्राह्मण म्हणतो ।",
  "419": "जो सर्व प्राणिमात्रांची उत्पत्ती आणि अंत जाणतो, जो पूर्णपणे अनासक्त, सन्मार्गावर चालणारा आणि सुज्ञ आहे, त्याला मी ब्राह्मण म्हणतो ॥",
  "420": "ज्याची गती देव, गंधर्व वा मानव कोणीही जाणू शकत नाही, ज्याचे सर्व आश्रव (दोष) क्षीण झाले आहेत, त्याला मी ब्राह्मण म्हणतो ।",
  "421": "ज्याचे भूत, वर्तमान आणि भविष्यात काहीही भौतिक उरलेले नाही, जो कशाचाही परिग्रह करीत नाही, त्याला मी ब्राह्मण म्हणतो ॥",
  "422": "जो वृषभाप्रमाणे बलवान, श्रेष्ठ, वीर, महर्षी आणि विजेता आहे; जो तृष्णाहीन, निष्पाप आणि सुज्ञानी आहे, त्याला मी ब्राह्मण म्हणतो ।",
  "423": "जो पूर्व-जन्म जाणतो, स्वर्ग व नरक साक्षात पाहतो, ज्याचे पुनर्जन्म संपुष्टात आले आहेत, जो प्रज्ञावान व मननशील असून ज्याने जीवनाचे अंतिम ध्येय (निर्वाण) प्राप्त केले आहे, त्याला मी ब्राह्मण म्हणतो ॥"
};
